    return (
        <>
        <Navbar />
        <div className="container p-5">
            <div className="row">
                <div className="col-6">

                </div>
                <div className="col-6">
                    <img src={ projectImage } alt="jual buku" />
                </div>
            </div>
        </div>
        </>
    )
}
